_TRANSIENT_UC_FIELDS = frozenset({
    '_needs_fix', '_static_validation_retry_done', '_retry_attempt',
    'sql_generation_status', 'sql_validation_status', 'column_validation_status',
    'sql_validation_error', 'cte_chaining_status', 'repeated_with_status',
    'format_string_status', 'enrichment_propagation_status', 'dead_cte_status',
    'column_ref_groupby_status', 'unquoted_coalesce_status',
    'lateral_alias_window_status', 'agg_without_over_status',
    'pii_leak_status', 'source_col_hallucination_status',
    'distinct_window_status', 'scalar_subq_over_status',
    'window_inside_agg_status', 'window_over_group_by_status',
    'ai_forecast_named_struct_status', 'fs_col_availability_status',
    'cte_col_ref_status', 'directly_involved_schema',
    '_pending_sub_batch_results',
})

def _strip_transient_fields(use_case: dict) -> dict:
    """Remove transient/validation fields from a use case dict to reduce memory footprint."""
    for field in _TRANSIENT_UC_FIELDS:
        use_case.pop(field, None)
    return use_case

def _force_gc(logger=None, reason: str = ""):
    """Force garbage collection and log memory stats."""
    gc.collect()
    try:
        import psutil
        proc = psutil.Process(os.getpid())
        mem_mb = proc.memory_info().rss / (1024 * 1024)
        if logger:
            logger.info(f"🧹 GC forced{f' ({reason})' if reason else ''}: RSS={mem_mb:.0f} MB")
    except ImportError:
        if logger:
            logger.debug(f"🧹 GC forced{f' ({reason})' if reason else ''}")


